local E = unpack(ElvUI)
local TUI = E:GetModule('TrenchyUI')

local PROFILE_NAME = 'TrenchyUI'

local profileString = 'BW2:'

function TUI:ApplyBigWigsProfile(callback)
	if not BigWigsAPI then
		if callback then callback(false) end
		return
	end

	BigWigsAPI.RegisterProfile('ElvUI_TrenchyUI', profileString, PROFILE_NAME, callback)
end
